+import type { AnyColumn } from '~/column.ts';
+import { sql, type SQL, type SQLWrapper } from '../sql.ts';
+
+type WindowExpression = SQLWrapper;
+type WindowExpressionData<T extends WindowExpression> = T extends AnyColumn ? T['_']['data']
+	: T extends SQL<infer TData> ? TData
+	: unknown;
+
+export interface WindowSpec {
+	partitionBy?: WindowExpression | WindowExpression[];
+	orderBy?: WindowExpression | WindowExpression[];
+	frame?: WindowFrame;
+}
+
+export interface WindowFrame {
+	readonly type: 'rows' | 'range';
+	readonly from: WindowBoundary;
+	readonly to: WindowBoundary;
+}
+
+type WindowBoundary = { readonly kind: 'unbounded preceding' | 'current row' | 'unbounded following' }
+	| { readonly kind: 'preceding' | 'following'; readonly value: number };
+
+export const unboundedPreceding: WindowBoundary = { kind: 'unbounded preceding' };
+export const currentRow: WindowBoundary = { kind: 'current row' };
+export const unboundedFollowing: WindowBoundary = { kind: 'unbounded following' };
+
+function validatePosition(name: string, value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer; received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowBoundary {
+	validatePosition('preceding', value);
+	return { kind: 'preceding', value };
+}
+
+export function following(value: number): WindowBoundary {
+	validatePosition('following', value);
+	return { kind: 'following', value };
+}
+
+function boundaryPosition(boundary: WindowBoundary): number {
+	switch (boundary.kind) {
+		case 'unbounded preceding': return -Infinity;
+		case 'preceding': return -boundary.value;
+		case 'current row': return 0;
+		case 'following': return boundary.value;
+		case 'unbounded following': return Infinity;
+	}
+}
+
+function makeFrame(type: WindowFrame['type'], { from, to }: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (boundaryPosition(from) > boundaryPosition(to)) {
+		throw new Error('Window frame "from" boundary must not be ordered after "to" boundary');
+	}
+	return { type, from, to };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return makeFrame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return makeFrame('range', spec);
+}
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	return 'value' in boundary ? sql.raw(`${boundary.value} ${boundary.kind}`) : sql.raw(boundary.kind);
+}
+
+export function buildWindowSpec(spec: WindowSpec): SQL {
+	const parts: SQL[] = [];
+	if (spec.partitionBy) {
+		parts.push(sql`partition by ${sql.join(Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy], sql`, `)}`);
+	}
+	if (spec.orderBy) {
+		parts.push(sql`order by ${sql.join(Array.isArray(spec.orderBy) ? spec.orderBy : [spec.orderBy], sql`, `)}`);
+	}
+	if (spec.frame) {
+		parts.push(sql`${sql.raw(spec.frame.type)} between ${boundarySql(spec.frame.from)} and ${boundarySql(spec.frame.to)}`);
+	}
+	return sql.join(parts, sql` `);
+}
+
+class WindowFunction<T> {
+	constructor(private readonly expression: SQL<T>) {}
+
+	over(spec: WindowSpec | string): SQL<T> {
+		return typeof spec === 'string'
+			? sql`${this.expression} over ${sql.identifier(spec)}`
+			: sql`${this.expression} over (${buildWindowSpec(spec)})`;
+	}
+}
+
+function windowFunction<T>(name: string, args: SQL[]): WindowFunction<T> {
+	return new WindowFunction(sql`${sql.raw(name)}(${sql.join(args, sql`, `)})`);
+}
+
+function positionalArgument(name: string, value: number): SQL {
+	if (!Number.isInteger(value) || value <= 0) {
+		throw new Error(`${name}() requires a positive integer; received ${value}`);
+	}
+	return sql.raw(String(value));
+}
+
+function optionalOffset(value: number | undefined): SQL[] {
+	return value === undefined ? [] : [sql.raw(String(value))];
+}
+
+export function rowNumber(): WindowFunction<number> { return windowFunction('row_number', []); }
+export function rank(): WindowFunction<number> { return windowFunction('rank', []); }
+export function denseRank(): WindowFunction<number> { return windowFunction('dense_rank', []); }
+export function ntile(value: number): WindowFunction<number> { return windowFunction('ntile', [positionalArgument('ntile', value)]); }
+export function percentRank(): WindowFunction<number> { return windowFunction('percent_rank', []); }
+export function cumeDist(): WindowFunction<number> { return windowFunction('cume_dist', []); }
+
+export function lag<T extends WindowExpression>(value: T): WindowFunction<WindowExpressionData<T> | null>;
+export function lag<T extends WindowExpression>(value: T, offset: number): WindowFunction<WindowExpressionData<T> | null>;
+export function lag<T extends WindowExpression>(value: T, offset: number | undefined, defaultValue: unknown): WindowFunction<Exclude<WindowExpressionData<T>, null>>;
+export function lag<T extends WindowExpression>(value: T, offset?: number, defaultValue?: unknown): WindowFunction<WindowExpressionData<T> | null> {
+	const args = [sql`${value}`, ...optionalOffset(offset)];
+	if (arguments.length === 3) args.push(sql`${defaultValue}`);
+	return windowFunction('lag', args);
+}
+
+export function lead<T extends WindowExpression>(value: T): WindowFunction<WindowExpressionData<T> | null>;
+export function lead<T extends WindowExpression>(value: T, offset: number): WindowFunction<WindowExpressionData<T> | null>;
+export function lead<T extends WindowExpression>(value: T, offset: number | undefined, defaultValue: unknown): WindowFunction<Exclude<WindowExpressionData<T>, null>>;
+export function lead<T extends WindowExpression>(value: T, offset?: number, defaultValue?: unknown): WindowFunction<WindowExpressionData<T> | null> {
+	const args = [sql`${value}`, ...optionalOffset(offset)];
+	if (arguments.length === 3) args.push(sql`${defaultValue}`);
+	return windowFunction('lead', args);
+}
+
+export function firstValue<T extends WindowExpression>(value: T): WindowFunction<WindowExpressionData<T> | null> { return windowFunction('first_value', [sql`${value}`]); }
+export function lastValue<T extends WindowExpression>(value: T): WindowFunction<WindowExpressionData<T> | null> { return windowFunction('last_value', [sql`${value}`]); }
+export function nthValue<T extends WindowExpression>(value: T, nth: number): WindowFunction<WindowExpressionData<T> | null> { return windowFunction('nth_value', [sql`${value}`, positionalArgument('nthValue', nth)]); }
+
+export function windowSum(value: WindowExpression): WindowFunction<string | null> { return windowFunction('sum', [sql`${value}`]); }
+export function windowAvg(value: WindowExpression): WindowFunction<string | null> { return windowFunction('avg', [sql`${value}`]); }
+export function windowMin<T extends WindowExpression>(value: T): WindowFunction<WindowExpressionData<T> | null> { return windowFunction('min', [sql`${value}`]); }
+export function windowMax<T extends WindowExpression>(value: T): WindowFunction<WindowExpressionData<T> | null> { return windowFunction('max', [sql`${value}`]); }
+export function windowCount(value?: WindowExpression): WindowFunction<number> { return windowFunction('count', [value ? sql`${value}` : sql.raw('*')]); }
